    if (start === -1) break;
    const end = text.indexOf(WORKING_MEMORY_END_TAG, start + WORKING_MEMORY_START_TAG.length);
    if (end === -1) break;
    results.push(text.substring(start, end + WORKING_MEMORY_END_TAG.length));
